from kafka import KafkaProducer
import json
from flask import Flask, request
from urllib.parse import urlparse

app = Flask(__name__)

# Set up Kafka producer with SSL/TLS encryption and validation
producer = KafkaProducer(bootstrap_servers=['localhost:9092'],
                         security_protocol='SSL',
                         ssl_check_hostname=False,
                         ssl_ca_cert='/path/to/ca-cert.pem',
                         ssl_certfile='/path/to/client-cert.pem',
                         ssl_keyfile='/path/to/client-key.pem')

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    message = json.loads(request.data)

    # Validate topic name to prevent injection attacks
    if not isinstance(topic_name, str) or len(topic_name.strip()) == 0:
        return 'Invalid topic name', 400

    # Validate message content to prevent data tampering
    if not isinstance(message, dict):
        return 'Invalid message format', 400

    try:
        producer.send(topic_name, value=json.dumps(message).encode('utf-8'))
        return 'Message published successfully'
    except Exception as e:
        return f'Error publishing message: {str(e)}'

if __name__ == '__main__':
    app.run(debug=True)